// Segment rotation by weekday (Mon=CMO, Tue=CIO, Wed=Doctors, Thu=Admin, Fri=Doctors). Weekend = halt.
const dow = $now.weekday; // 1=Mon .. 7=Sun (luxon)
const map = { 1:'CMO', 2:'CIO', 3:'DOCTOR', 4:'ADMIN', 5:'DOCTOR' };
const segment = map[dow];
if (!segment) return []; // weekend -> no scrape

// === Active wave location IDs ===
// Wave 1 = IN + GCC + SG | Wave 2 = UK/IE/NL/SE/DK/NO/FI/BE | Wave 3 = US/DE/AT/CH/FR.
const WAVE = {
  1: ["102713980","104305776","100459316","104170880","103239229","103619019","100425729","102454443"], // IN, AE, SA, QA, KW, OM, BH, SG
  2: ["101165590","104738515","102890719","105117694","104514075","103819153","100456013","100565514"], // UK, IE, NL, SE, DK, NO, FI, BE
  3: ["103644278","101282230","103883259","106693272","105015875"]  // US, DE, AT, CH, FR
};
// Auto-rotate the active wave every run so no single region set saturates.
// First run after deploy => Wave 2 (Wave 1 is exhausted), then 3 -> 1 -> 2 -> 3 ...
const sd = $getWorkflowStaticData('global');
sd.wf1_wave = ((sd.wf1_wave || 1) % 3) + 1;
const ACTIVE_WAVE = sd.wf1_wave;
const locations = WAVE[ACTIVE_WAVE];

const INDUSTRY = ["14","13","3238","124"]; // Hospitals & Health Care + adjacent
const defs = {
  CMO:    { keywords:'"Chief Medical Officer" OR "Medical Director" OR "Clinical Director"', seniority:["cxo","vice_president","director"], headcount:[{min:51,max:10000}], posted:false, search_name:'Hosp_CMO_Global_Active', limit:100 },
  CIO:    { keywords:'"Chief Information Officer" OR CIO OR "Chief Digital Officer" OR "Head of Digital" OR "Chief Medical Information Officer" OR CMIO', seniority:["cxo","vice_president","director"], headcount:[{min:201,max:10000}], posted:false, search_name:'Hosp_CIO_Global_Active', limit:100 },
  ADMIN:  { keywords:'"Hospital Administrator" OR "Director Operations" OR "Chief Operating Officer"', seniority:["cxo","vice_president","director","experienced_manager"], headcount:[{min:51,max:10000}], posted:false, search_name:'Hosp_Admin_Global_Active', limit:100 },
  DOCTOR: { keywords:'physician OR consultant OR specialist OR oncologist OR "medical oncologist" OR "hemato-oncologist"', seniority:[], headcount:[], posted:true, search_name:'Doc_Clinical_Active', limit:40 }
};
const d = defs[segment];
const searchPayload = { api:'sales_navigator', category:'people', keywords:d.keywords, location:{ include: locations }, industry:{ include: INDUSTRY }, messaged_recently:false };
if (d.seniority.length) searchPayload.seniority = { include: d.seniority };
if (d.headcount.length) searchPayload.company_headcount = d.headcount;
if (d.posted) searchPayload.posted_on_linkedin = true; // mandatory ONLY for the doctor track
return [{ json: { segment, search_name:d.search_name, limit:d.limit, wave:ACTIVE_WAVE, searchPayload } }];

const existingRows = $('leads').all();
const existingIds = new Set();
for (const row of existingRows) { const id = row.json.provider_id; if (id && id !== 'N/A') existingIds.add(id); }

const cfg = $('segmentConfig').first().json;
const segment = cfg.segment || '';
const searchName = cfg.search_name || '';

function deriveRegion(loc) {
  const s = (loc || '').toLowerCase();
  const map = [
    ['IN','India',['india','mumbai','delhi','bengaluru','bangalore','hyderabad','chennai','pune','kolkata','ahmedabad','kochi','lucknow','gurgaon','gurugram','noida']],
    ['AE','United Arab Emirates',['united arab emirates','uae','dubai','abu dhabi','sharjah']],
    ['SA','Saudi Arabia',['saudi','riyadh','jeddah','dammam','mecca','medina']],
    ['QA','Qatar',['qatar','doha']],
    ['KW','Kuwait',['kuwait']],
    ['OM','Oman',['oman','muscat']],
    ['SG','Singapore',['singapore']],
    ['UK','United Kingdom',['united kingdom','london','england','scotland','wales','manchester','birmingham','edinburgh','glasgow','leeds']],
    ['IE','Ireland',['ireland','dublin','cork']],
    ['NL','Netherlands',['netherlands','amsterdam','rotterdam','utrecht','the hague']],
    ['BE','Belgium',['belgium','brussels','antwerp','ghent']],
    ['SE','Sweden',['sweden','stockholm','gothenburg','malmo']],
    ['DK','Denmark',['denmark','copenhagen','aarhus']],
    ['NO','Norway',['norway','oslo','bergen']],
    ['FI','Finland',['finland','helsinki','espoo']],
    ['DE','Germany',['germany','berlin','munich','münchen','hamburg','frankfurt','cologne','köln','stuttgart']],
    ['AT','Austria',['austria','vienna','wien','graz','salzburg']],
    ['CH','Switzerland',['switzerland','zurich','zürich','geneva','genève','basel','bern','lausanne']],
    ['FR','France',['france','paris','lyon','marseille','toulouse','nice','bordeaux']],
    ['US_ET','United States',['united states','usa',', us','new york','boston','chicago','houston','los angeles','san francisco','seattle','atlanta','dallas','washington','philadelphia','miami','texas','california','florida','massachusetts','new jersey']]
  ];
  for (const [region,country,keys] of map) for (const k of keys) if (s.includes(k)) return { region, country };
  return { region:'', country:'' };
}

const allPeople = $input.all().flatMap(item => item.json?.items ?? []);
if (allPeople.length === 0) return [];
const seen = new Set();
const out = [];
for (const p of allPeople) {
  const id = p.id;
  if (!id || existingIds.has(id) || seen.has(id)) continue;
  seen.add(id);
  const cleanUrl = p.public_identifier ? `https://www.linkedin.com/in/${p.public_identifier}` : '';
  const company = (p.current_positions && p.current_positions[0] && p.current_positions[0].company) || '';
  const loc = p.location || 'N/A';
  const { region, country } = deriveRegion(loc);
  const leadId = 'LEAD-' + Date.now().toString(36).slice(-3).toUpperCase() + Math.random().toString(36).substring(2,6).toUpperCase();
  out.push({ json: {
    Lead_ID: leadId, Name: p.name || 'Unknown', Headline: p.headline || 'N/A', Location: loc,
    Public_Identifier: p.public_identifier || 'N/A', Profile_URL: cleanUrl,
    Network_Distance: p.network_distance || 'N/A', Verified: p.verified ? 'Yes' : 'No',
    Shared_Connections: p.shared_connections_count ?? 0, ID: id,
    Hospital_Name: company, Region: region, Country: country, Segment: segment,
    Search_Name: searchName, Template_Safe: company ? 'TRUE' : 'FALSE'
  }});
}
return out;

const raw = ($input.first().json.output ?? '[]').toString();
let scored = [];
try { scored = JSON.parse(raw.replace(/```json|```/g,'').trim()); } catch (e) { scored = []; }
const byId = {};
for (const s of (Array.isArray(scored) ? scored : [])) byId[s.id] = s;
const out = [];
for (const it of $('parser').all()) {
  const lead = it.json;
  const s = byId[lead.ID] || { tier:'B', segment_confirmed:true, reason:'unscored-default' };
  if (String(s.tier).toUpperCase() === 'REJECT') continue;
  out.push({ json: { ...lead, Tier: String(s.tier).toUpperCase(), Segment_Confirmed: s.segment_confirmed, Qual_Reason: s.reason } });
}
return out;

const lead = $('loop').item.json;
let lastPost = '', topic = '';
const resp = $input.first().json || {};
const arr = Array.isArray(resp) ? resp : (resp.items || resp.posts || []);
if (Array.isArray(arr) && arr.length) {
  arr.sort((a,b) => new Date(b.parsed_datetime || b.date || 0) - new Date(a.parsed_datetime || a.date || 0));
  lastPost = arr[0].parsed_datetime || arr[0].date || '';
  topic = (arr[0].text || '').replace(/\s+/g,' ').trim().slice(0,80);
}
return [{ json: { ...lead, Last_Post_Date: lastPost, Topic: topic } }];

// Reset the per-run accumulator and snapshot existing provider_ids (from the aggregated leads sheet) for dedup.
// Done here (outside the loop) because $('leads') returns empty when referenced from inside the pager loop.
const sd = $getWorkflowStaticData('global');
sd.wf1_people = [];
sd.wf1_page = 0;
const rows = ($input.first().json && $input.first().json.leads) || [];
const ex = [];
for (const r of rows) { const id = r && r.provider_id; if (id && id !== 'N/A') ex.push(id); }
sd.wf1_existing = ex;
return [{ json: { cursor: '' } }];

// Accumulate Unipile search pages until we have enough NEW (un-scraped) leads or hit the page cap.
const sd = $getWorkflowStaticData('global');
const resp = $input.first().json || {};
const pageItems = Array.isArray(resp.items) ? resp.items : [];
sd.wf1_people = (sd.wf1_people || []).concat(pageItems);
sd.wf1_page = (sd.wf1_page || 0) + 1;
const cursor = resp.cursor || '';

// Dedup against the snapshot taken in pageStart (NOT $('leads') -- that is empty inside the loop).
const existing = new Set(sd.wf1_existing || []);
const seen = new Set();
let newCount = 0;
for (const p of sd.wf1_people) { const id = p.id; if (!id || existing.has(id) || seen.has(id)) continue; seen.add(id); newCount++; }

const MAX_PAGES = 8;
const TARGET_NEW = 50;
const more = !!cursor && sd.wf1_page < MAX_PAGES && newCount < TARGET_NEW;
if (more) return [{ json: { cursor } }]; // loop back to search with next cursor

const all = sd.wf1_people || [];
sd.wf1_people = [];
sd.wf1_page = 0;
return [{ json: { items: all } }]; // exit: hand all accumulated people to parser (it flattens .items)
